CustomFunction.Calculation:
// Returns "" for the first clause (index = 0),
// " AND " or " OR " for subsequent clauses.
If ( index = 0 ;
	"" ;
// ELSE
	If ( Exact ( boolean ; "or" ) ;
		" OR " ;
	// ELSE
		" AND "
	)
)

// Recursively builds N comma-separated ? placeholders for IN clauses.
// Call with index = 0. Example: count=3 → "?, ?, ?"
If ( index + 1 < count ;
	"?, " & QueryBuildInPlaceholders_cf ( count ; index + 1 ) ;
// ELSE
	"?"
)

// Recursively appends values from a ¶-delimited list to the query's
// bindings array. Call with index = 1 (GetValue is 1-based).
// Used by QueryWhereIn_cf to add N bindings in one pass.
Let
(
[
_bindingCount = JSONGetElement ( query ; "bindingCount" ) ;
_value = GetValue ( values ; index ) ;
_q1 = JSONSetElement ( query ; "bindings[" & _bindingCount & "]" ; _value ; JSONString ) ;
_q2 = JSONSetElement ( _q1 ; "bindingCount" ; _bindingCount + 1 ; JSONNumber )
];
If ( index < valueCount ;
	QueryAppendBindings_cf ( _q2 ; values ; valueCount ; index + 1 ) ;
// ELSE
	_q2
)
)

// Recursively appends bindings from a JSON array (sourceBindings) into
// outerQuery's bindings array. Call with index = 0.
// Analogous to QueryAppendBindings_cf but reads from a JSON array rather
// than a ¶-delimited list. Used by QueryWhereInSubquery_cf.
Let
(
[
_bindingCount = JSONGetElement ( outerQuery ; "bindingCount" ) ;
_value = JSONGetElement ( sourceBindings ; "[" & index & "]" ) ;
_q1 = JSONSetElement ( outerQuery ; "bindings[" & _bindingCount & "]" ; _value ; JSONString ) ;
_q2 = JSONSetElement ( _q1 ; "bindingCount" ; _bindingCount + 1 ; JSONNumber )
];
If ( index + 1 < sourceCount ;
	QueryMergeBindings_cf ( _q2 ; sourceBindings ; sourceCount ; index + 1 ) ;
// ELSE
	_q2
)
)

// Rebuilds outerQuery's bindings array as [prefixBindings...][suffixBindings...].
// prefixBindings is a subquery's bindings JSON array (written first because
// the subquery appears in FROM, before WHERE in SQL). suffixBindings is the
// outer query's existing bindings JSON array. Call with index = 0.
// On the final iteration writes the new bindingCount = prefixCount + suffixCount.
// Used by QueryFromSubquery_cf to ensure correct ? placeholder order.
Let
(
[
_total = prefixCount + suffixCount ;
_value = If ( index < prefixCount ;
	JSONGetElement ( prefixBindings ; "[" & index & "]" ) ;
	JSONGetElement ( suffixBindings ; "[" & ( index - prefixCount ) & "]" )
	) ;
_q1 = JSONSetElement ( outerQuery ; "bindings[" & index & "]" ; _value ; JSONString )
];
If ( index + 1 < _total ;
	QueryPrependBindings_cf ( _q1 ; prefixBindings ; prefixCount ; suffixBindings ; suffixCount ; index + 1 ) ;
// ELSE last element: write final bindingCount
	JSONSetElement ( _q1 ; "bindingCount" ; _total ; JSONNumber )
)
)

// Recursively builds the JOIN clause string.
// Call with index = 0. joins is the raw JSON array from the query object.
// Example output: "INNER JOIN invoice__ITEM ON CONTACT.id = invoice__ITEM.idContact"
Let
(
[
_join = JSONGetElement ( joins ; "[" & index & "]" ) ;
_type = JSONGetElement ( _join ; "type" ) ;
_table = JSONGetElement ( _join ; "table" ) ;
_first = JSONGetElement ( _join ; "first" ) ;
_operator = JSONGetElement ( _join ; "operator" ) ;
_second = JSONGetElement ( _join ; "second" ) ;
_keyword = If ( Exact ( _type ; "left" ) ; "LEFT JOIN" ; "INNER JOIN" ) ;
_clause = _keyword & " " & _table & " ON " & _first & " " & _operator & " " & _second ;
_rest = If ( index + 1 < joinCount ; " " & QueryBuildJoins_cf ( joins ; joinCount ; index + 1 ) ; "" )
];
_clause & _rest
)

// Recursively builds the WHERE clause body (excluding the "WHERE" keyword).
// Call with index = 0. wheres is the raw JSON array from the query object.
// Supported types: basic, in, null, notNull, between, inSubquery.
Let
(
[
_where = JSONGetElement ( wheres ; "[" & index & "]" ) ;
_type = JSONGetElement ( _where ; "type" ) ;
_column = JSONGetElement ( _where ; "column" ) ;
_operator = JSONGetElement ( _where ; "operator" ) ;
_boolean = JSONGetElement ( _where ; "boolean" ) ;
_valueCount = JSONGetElement ( _where ; "valueCount" ) ;
_prefix = QueryBuildWhereBooleanPrefix_cf ( _boolean ; index ) ;
_clause = Case (
	Exact ( _type ; "basic" ) ;
		_prefix & _column & " " & _operator & " ?" ;
	Exact ( _type ; "in" ) ;
		_prefix & _column & " IN (" & QueryBuildInPlaceholders_cf ( _valueCount ; 0 ) & ")" ;
	Exact ( _type ; "null" ) ;
		_prefix & _column & " IS NULL" ;
	Exact ( _type ; "notNull" ) ;
		_prefix & _column & " IS NOT NULL" ;
	Exact ( _type ; "between" ) ;
		_prefix & _column & " BETWEEN ? AND ?" ;
	Exact ( _type ; "inSubquery" ) ;
		_prefix & _column & " IN (" & JSONGetElement ( _where ; "sql" ) & ")" ;
	""
	) ;
_rest = If ( index + 1 < whereCount ; QueryBuildWheres_cf ( wheres ; whereCount ; index + 1 ) ; "" )
];
_clause & _rest
)

// Recursively builds the GROUP BY column list.
// Call with index = 0. groupBys is the raw JSON array from the query object.
// Example output: "CONTACT.type, CONTACT.status"
Let
(
[
_col = JSONGetElement ( groupBys ; "[" & index & "]" ) ;
_rest = If ( index + 1 < groupByCount ; ", " & QueryBuildGroupBys_cf ( groupBys ; groupByCount ; index + 1 ) ; "" )
];
_col & _rest
)

// Recursively builds the HAVING clause body (excluding the "HAVING" keyword).
// Call with index = 0. havings is the raw JSON array from the query object.
// Each having clause uses a ? placeholder bound in the bindings array.
Let
(
[
_having = JSONGetElement ( havings ; "[" & index & "]" ) ;
_column = JSONGetElement ( _having ; "column" ) ;
_operator = JSONGetElement ( _having ; "operator" ) ;
_boolean = JSONGetElement ( _having ; "boolean" ) ;
_prefix = QueryBuildWhereBooleanPrefix_cf ( _boolean ; index ) ;
_clause = _prefix & _column & " " & _operator & " ?" ;
_rest = If ( index + 1 < havingCount ; QueryBuildHavings_cf ( havings ; havingCount ; index + 1 ) ; "" )
];
_clause & _rest
)

// Recursively builds the ORDER BY column list.
// Call with index = 0. orderBys is the raw JSON array from the query object.
// Example output: "CONTACT.lastName ASC, CONTACT.firstName ASC"
Let
(
[
_orderBy = JSONGetElement ( orderBys ; "[" & index & "]" ) ;
_column = JSONGetElement ( _orderBy ; "column" ) ;
_direction = JSONGetElement ( _orderBy ; "direction" ) ;
_clause = _column & " " & _direction ;
_rest = If ( index + 1 < orderByCount ; ", " & QueryBuildOrderBys_cf ( orderBys ; orderByCount ; index + 1 ) ; "" )
];
_clause & _rest
)

// Recursively builds the binding argument string for use inside Evaluate().
// Call with index = 0. bindings is the raw JSON array from the query object.
// Each value is wrapped in Quote() to handle special characters safely.
// Example output: "Active" ; "customer" ; "prospect"
// This string is concatenated into the ExecuteSQL Evaluate expression.
Let
(
[
_value = JSONGetElement ( bindings ; "[" & index & "]" ) ;
_quoted = Quote ( _value ) ;
_rest = If ( index + 1 < bindingCount ; " ; " & QueryBuildBindingArgs_cf ( bindings ; bindingCount ; index + 1 ) ; "" )
];
_quoted & _rest
)

// Recursively converts a ¶-delimited column list to SQL column expressions.
// Delegates individual field conversion to QueryConvertField_cf.
// Other expressions (*, COUNT(*), already-dotted names, etc.) pass through unchanged.
// Call with index = 1 (GetValue is 1-based).
Let
(
[
_field = Trim ( GetValue ( columns ; index ) ) ;
_converted = QueryConvertField_cf ( _field ) ;
_rest = If ( index < columnCount ;
	", " & QueryBuildSelects_cf ( columns ; columnCount ; index + 1 ) ;
// ELSE
	""
	)
];
_converted & _rest
)

// Converts a FileMaker fully-qualified field name (Table::Field) to a
// quoted SQL dot-notation identifier ("Table"."Field"). Quote() is used for
// readability and automatic escaping. Expressions without :: pass through
// unchanged, so *, COUNT(*), and already-converted references are safe.
// Callers are responsible for resolving direct field references via GetFieldName()
// before passing to this function.
Let
(
[
_sepPos = Position ( field ; "::" ; 1 ; 1 )
];
If ( _sepPos > 0 ;
	Quote ( Left ( field ; _sepPos - 1 ) ) & "." & Quote ( Middle ( field ; _sepPos + 2 ; Length ( field ) ) ) ;
// ELSE
	field
)
)

// Recursively extracts a plain key name from each column expression in a
// ¶-delimited list, for use as JSON object property names.
// Extraction rules (applied to the original input before SQL conversion):
//   Table::Field  →  Field   (FM fully-qualified: take part after ::)
//   Table.field   →  field   (dot notation: take part after the dot)
//   anything else →  as-is   (e.g. *, COUNT(*))
// Call with index = 1.
Let
(
[
_expr = Trim ( GetValue ( columns ; index ) ) ;
_scopePos = Position ( _expr ; "::" ; 1 ; 1 ) ;
_dotPos = Position ( _expr ; "." ; 1 ; 1 ) ;
_key = Case (
	_scopePos > 0 ; Middle ( _expr ; _scopePos + 2 ; Length ( _expr ) ) ;
	_dotPos > 0 ; Middle ( _expr ; _dotPos + 1 ; Length ( _expr ) ) ;
	_expr
	) ;
_rest = If ( index < columnCount ;
	"¶" & QueryBuildSelectKeys_cf ( columns ; columnCount ; index + 1 ) ;
// ELSE
	""
	)
];
_key & _rest
)

// Recursively builds a single JSON object from parallel ¶-delimited lists
// of field values and key names. Call with index = 1 and obj = "{}".
// All values are stored as JSONString; numeric/date coercion is left to the caller.
Let
(
[
_key = GetValue ( keys ; index ) ;
_value = GetValue ( fields ; index ) ;
_newObj = JSONSetElement ( obj ; _key ; _value ; JSONString )
];
If ( index < keyCount ;
	QueryBuildJsonRow_cf ( _newObj ; fields ; keys ; keyCount ; index + 1 ) ;
// ELSE
	_newObj
)
)

// Recursively appends row objects to a JSON array.
// rawResult is the ExecuteSQL output with Char(28) field separators and ¶ row separators.
// Call with rowIndex = 1 and result = "[]".
Let
(
[
_rawRow = GetValue ( rawResult ; rowIndex ) ;
_fields = Substitute ( _rawRow ; Char ( 28 ) ; "¶" ) ;
_rowObj = QueryBuildJsonRow_cf ( "{}" ; _fields ; keys ; keyCount ; 1 ) ;
_newResult = JSONSetElement ( result ; "[" & ( rowIndex - 1 ) & "]" ; _rowObj ; JSONObject )
];
If ( rowIndex < rowCount ;
	QueryBuildJsonRows_cf ( _newResult ; rawResult ; rowCount ; keys ; keyCount ; rowIndex + 1 ) ;
// ELSE
	_newResult
)
)

Let
(
[
_fqName = GetFieldName ( table ) ;
_tableName = If ( Position ( _fqName ; "::" ; 1 ; 1 ) > 0 ; _fqName ; table ) ;
_table = Quote (
	If ( PatternCount ( _tableName ; "::" ) ;
		Left ( _tableName ; Position ( _tableName ; "::" ; 1 ; 1 ) - 1 ) ;
	// ELSE
		_tableName
	))
];
JSONSetElement ( "{}" ;
[ "table" ; _table ; JSONString ] ;
[ "selects" ; "*" ; JSONString ] ;
[ "selectKeys" ; "*" ; JSONString ] ;
[ "joins" ; "[]" ; JSONRaw ] ;
[ "joinCount" ; 0 ; JSONNumber ] ;
[ "wheres" ; "[]" ; JSONRaw ] ;
[ "whereCount" ; 0 ; JSONNumber ] ;
[ "groupBys" ; "[]" ; JSONRaw ] ;
[ "groupByCount" ; 0 ; JSONNumber ] ;
[ "havings" ; "[]" ; JSONRaw ] ;
[ "havingCount" ; 0 ; JSONNumber ] ;
[ "orderBys" ; "[]" ; JSONRaw ] ;
[ "orderByCount" ; 0 ; JSONNumber ] ;
[ "limit" ; "" ; JSONString ] ;
[ "offset" ; "" ; JSONString ] ;
[ "bindings" ; "[]" ; JSONRaw ] ;
[ "bindingCount" ; 0 ; JSONNumber ]
)
)

// Accepts a ¶-delimited list (e.g. from List() / GetFieldName()) or a
// comma-separated string. FileMaker fully-qualified names (Table::Field) are
// converted to quoted SQL dot notation ("Table"."Field"). Other expressions
// (*, COUNT(*), already-dotted names, raw SQL expressions, etc.) pass through
// unchanged — no separate QuerySelectRaw_cf is needed.
// Calls are additive: the first call after QueryNew_cf replaces the initial
// "*" sentinel; subsequent calls append to the existing column list.
Let
(
[
_normalized = Substitute ( Substitute ( columns ; ", " ; "¶" ) ; "," ; "¶" ) ;
_columnCount = ValueCount ( _normalized ) ;
_newSelects = QueryBuildSelects_cf ( _normalized ; _columnCount ; 1 ) ;
_newKeys = QueryBuildSelectKeys_cf ( _normalized ; _columnCount ; 1 ) ;
_existingSelects = JSONGetElement ( query ; "selects" ) ;
_existingKeys = JSONGetElement ( query ; "selectKeys" ) ;
_isWildcard = Exact ( _existingSelects ; "*" ) ;
_finalSelects = If ( _isWildcard ; _newSelects ; _existingSelects & ", " & _newSelects ) ;
_finalKeys = If ( _isWildcard ; _newKeys ; _existingKeys & ¶ & _newKeys ) ;
_q1 = JSONSetElement ( query ; "selects" ; _finalSelects ; JSONString )
];
JSONSetElement ( _q1 ; "selectKeys" ; _finalKeys ; JSONString )
)

Let
(
[
_whereCount = JSONGetElement ( query ; "whereCount" ) ;
_bindingCount = JSONGetElement ( query ; "bindingCount" ) ;
_fqName = GetFieldName ( column ) ;
_col = If ( Position ( _fqName ; "::" ; 1 ; 1 ) > 0 ; _fqName ; column ) ;
_column = QueryConvertField_cf ( _col ) ;
_whereObj = JSONSetElement ( "{}" ;
	[ "type" ; "basic" ; JSONString ] ;
	[ "column" ; _column ; JSONString ] ;
	[ "operator" ; operator ; JSONString ] ;
	[ "boolean" ; "and" ; JSONString ]
	) ;
_q1 = JSONSetElement ( query ; "wheres[" & _whereCount & "]" ; _whereObj ; JSONObject ) ;
_q2 = JSONSetElement ( _q1 ; "whereCount" ; _whereCount + 1 ; JSONNumber ) ;
_q3 = JSONSetElement ( _q2 ; "bindings[" & _bindingCount & "]" ; value ; JSONString ) ;
_q4 = JSONSetElement ( _q3 ; "bindingCount" ; _bindingCount + 1 ; JSONNumber )
];
_q4
)

Let
(
[
_whereCount = JSONGetElement ( query ; "whereCount" ) ;
_bindingCount = JSONGetElement ( query ; "bindingCount" ) ;
_fqName = GetFieldName ( column ) ;
_col = If ( Position ( _fqName ; "::" ; 1 ; 1 ) > 0 ; _fqName ; column ) ;
_column = QueryConvertField_cf ( _col ) ;
_whereObj = JSONSetElement ( "{}" ;
	[ "type" ; "basic" ; JSONString ] ;
	[ "column" ; _column ; JSONString ] ;
	[ "operator" ; operator ; JSONString ] ;
	[ "boolean" ; "or" ; JSONString ]
	) ;
_q1 = JSONSetElement ( query ; "wheres[" & _whereCount & "]" ; _whereObj ; JSONObject ) ;
_q2 = JSONSetElement ( _q1 ; "whereCount" ; _whereCount + 1 ; JSONNumber ) ;
_q3 = JSONSetElement ( _q2 ; "bindings[" & _bindingCount & "]" ; value ; JSONString ) ;
_q4 = JSONSetElement ( _q3 ; "bindingCount" ; _bindingCount + 1 ; JSONNumber )
];
_q4
)

// values is a ¶-delimited list of values.
// Appends an IN where clause and N bindings (one per value).
Let
(
[
_whereCount = JSONGetElement ( query ; "whereCount" ) ;
_valueCount = ValueCount ( values ) ;
_fqName = GetFieldName ( column ) ;
_col = If ( Position ( _fqName ; "::" ; 1 ; 1 ) > 0 ; _fqName ; column ) ;
_column = QueryConvertField_cf ( _col ) ;
_whereObj = JSONSetElement ( "{}" ;
	[ "type" ; "in" ; JSONString ] ;
	[ "column" ; _column ; JSONString ] ;
	[ "valueCount" ; _valueCount ; JSONNumber ] ;
	[ "boolean" ; "and" ; JSONString ]
	) ;
_q1 = JSONSetElement ( query ; "wheres[" & _whereCount & "]" ; _whereObj ; JSONObject ) ;
_q2 = JSONSetElement ( _q1 ; "whereCount" ; _whereCount + 1 ; JSONNumber ) ;
_q3 = QueryAppendBindings_cf ( _q2 ; values ; _valueCount ; 1 )
];
_q3
)

// Appends WHERE column IN (SELECT ...) using a fully-assembled fmorm
// subquery object. The subquery's SQL is embedded directly; its bindings
// are appended to the outer query's bindings in WHERE-clause order (correct
// because the IN clause is appended last, after existing WHERE conditions).
// NOTE: IN subqueries require FileMaker 17+. Correlated subqueries (where
// the inner SELECT references an outer column) are not reliably supported.
Let
(
[
_whereCount = JSONGetElement ( query ; "whereCount" ) ;
_fqName = GetFieldName ( column ) ;
_col = If ( Position ( _fqName ; "::" ; 1 ; 1 ) > 0 ; _fqName ; column ) ;
_column = QueryConvertField_cf ( _col ) ;
_subSql = QueryToSQL_cf ( subquery ) ;
_subBindings = JSONGetElement ( subquery ; "bindings" ) ;
_subBindingCount = JSONGetElement ( subquery ; "bindingCount" ) ;
_whereObj = JSONSetElement ( "{}" ;
	[ "type" ; "inSubquery" ; JSONString ] ;
	[ "column" ; _column ; JSONString ] ;
	[ "sql" ; _subSql ; JSONString ] ;
	[ "boolean" ; "and" ; JSONString ]
	) ;
_q1 = JSONSetElement ( query ; "wheres[" & _whereCount & "]" ; _whereObj ; JSONObject ) ;
_q2 = JSONSetElement ( _q1 ; "whereCount" ; _whereCount + 1 ; JSONNumber ) ;
_q3 = If ( _subBindingCount > 0 ;
	QueryMergeBindings_cf ( _q2 ; _subBindings ; _subBindingCount ; 0 ) ;
	_q2
	)
];
_q3
)

// Replaces the FROM table with a derived table: FROM (SELECT ...) alias.
// The table name set in QueryNew_cf is discarded and replaced by the subquery
// expression. alias is a plain SQL identifier — use a simple string like "sub".
// The subquery's bindings are prepended to any existing outer bindings because
// the FROM clause appears before WHERE in the SQL string, so its ? placeholders
// must come first in the bindings array for ExecuteSQL to match them correctly.
// NOTE: Derived tables (subqueries in FROM) are functional in FileMaker 19.x
// but are not formally documented by Claris. Test in your target FM version.
// Avoid QueryLimit_cf / QueryOffset_cf on the inner query — FETCH FIRST inside
// a subquery is not supported in all FM versions.
Let
(
[
_subSql = QueryToSQL_cf ( subquery ) ;
_derivedTable = "(" & _subSql & ") " & alias ;
_subBindings = JSONGetElement ( subquery ; "bindings" ) ;
_subBindingCount = JSONGetElement ( subquery ; "bindingCount" ) ;
_outerBindings = JSONGetElement ( outerQuery ; "bindings" ) ;
_outerBindingCount = JSONGetElement ( outerQuery ; "bindingCount" ) ;
_q1 = JSONSetElement ( outerQuery ; "table" ; _derivedTable ; JSONString ) ;
_q2 = If ( _subBindingCount > 0 ;
	QueryPrependBindings_cf ( _q1 ; _subBindings ; _subBindingCount ; _outerBindings ; _outerBindingCount ; 0 ) ;
	_q1
	)
];
_q2
)

Let
(
[
_whereCount = JSONGetElement ( query ; "whereCount" ) ;
_fqName = GetFieldName ( column ) ;
_col = If ( Position ( _fqName ; "::" ; 1 ; 1 ) > 0 ; _fqName ; column ) ;
_column = QueryConvertField_cf ( _col ) ;
_whereObj = JSONSetElement ( "{}" ;
	[ "type" ; "null" ; JSONString ] ;
	[ "column" ; _column ; JSONString ] ;
	[ "boolean" ; "and" ; JSONString ]
	)
];
JSONSetElement (
	JSONSetElement ( query ; "wheres[" & _whereCount & "]" ; _whereObj ; JSONObject ) ;
	"whereCount" ; _whereCount + 1 ; JSONNumber
)
)

Let
(
[
_whereCount = JSONGetElement ( query ; "whereCount" ) ;
_fqName = GetFieldName ( column ) ;
_col = If ( Position ( _fqName ; "::" ; 1 ; 1 ) > 0 ; _fqName ; column ) ;
_column = QueryConvertField_cf ( _col ) ;
_whereObj = JSONSetElement ( "{}" ;
	[ "type" ; "notNull" ; JSONString ] ;
	[ "column" ; _column ; JSONString ] ;
	[ "boolean" ; "and" ; JSONString ]
	)
];
JSONSetElement (
	JSONSetElement ( query ; "wheres[" & _whereCount & "]" ; _whereObj ; JSONObject ) ;
	"whereCount" ; _whereCount + 1 ; JSONNumber
)
)

Let
(
[
_joinCount = JSONGetElement ( query ; "joinCount" ) ;
_fqName = GetFieldName ( table ) ;
_tableName = If ( Position ( _fqName ; "::" ; 1 ; 1 ) > 0 ; _fqName ; table ) ;
_table = Quote (
	If ( PatternCount ( _tableName ; "::" ) ;
		Left ( _tableName ; Position ( _tableName ; "::" ; 1 ; 1 ) - 1 ) ;
	// ELSE
		_tableName
	)) ;
_fqFirst = GetFieldName ( first ) ;
_first = QueryConvertField_cf ( If ( Position ( _fqFirst ; "::" ; 1 ; 1 ) > 0 ; _fqFirst ; first ) ) ;
_fqSecond = GetFieldName ( second ) ;
_second = QueryConvertField_cf ( If ( Position ( _fqSecond ; "::" ; 1 ; 1 ) > 0 ; _fqSecond ; second ) ) ;
_joinObj = JSONSetElement ( "{}" ;
	[ "type" ; "inner" ; JSONString ] ;
	[ "table" ; _table ; JSONString ] ;
	[ "first" ; _first ; JSONString ] ;
	[ "operator" ; operator ; JSONString ] ;
	[ "second" ; _second ; JSONString ]
	) ;
_q1 = JSONSetElement ( query ; "joins[" & _joinCount & "]" ; _joinObj ; JSONObject ) ;
_q2 = JSONSetElement ( _q1 ; "joinCount" ; _joinCount + 1 ; JSONNumber )
];
_q2
)

Let
(
[
_joinCount = JSONGetElement ( query ; "joinCount" ) ;
_fqName = GetFieldName ( table ) ;
_tableName = If ( Position ( _fqName ; "::" ; 1 ; 1 ) > 0 ; _fqName ; table ) ;
_table = Quote (
	If ( PatternCount ( _tableName ; "::" ) ;
		Left ( _tableName ; Position ( _tableName ; "::" ; 1 ; 1 ) - 1 ) ;
	// ELSE
		_tableName
	)) ;
_fqFirst = GetFieldName ( first ) ;
_first = QueryConvertField_cf ( If ( Position ( _fqFirst ; "::" ; 1 ; 1 ) > 0 ; _fqFirst ; first ) ) ;
_fqSecond = GetFieldName ( second ) ;
_second = QueryConvertField_cf ( If ( Position ( _fqSecond ; "::" ; 1 ; 1 ) > 0 ; _fqSecond ; second ) ) ;
_joinObj = JSONSetElement ( "{}" ;
	[ "type" ; "left" ; JSONString ] ;
	[ "table" ; _table ; JSONString ] ;
	[ "first" ; _first ; JSONString ] ;
	[ "operator" ; operator ; JSONString ] ;
	[ "second" ; _second ; JSONString ]
	) ;
_q1 = JSONSetElement ( query ; "joins[" & _joinCount & "]" ; _joinObj ; JSONObject ) ;
_q2 = JSONSetElement ( _q1 ; "joinCount" ; _joinCount + 1 ; JSONNumber )
];
_q2
)

// direction defaults to "ASC" when empty.
Let
(
[
_orderByCount = JSONGetElement ( query ; "orderByCount" ) ;
_dir = If ( IsEmpty ( direction ) ; "ASC" ; Upper ( direction ) ) ;
_fqName = GetFieldName ( column ) ;
_col = If ( Position ( _fqName ; "::" ; 1 ; 1 ) > 0 ; _fqName ; column ) ;
_column = QueryConvertField_cf ( _col ) ;
_orderByObj = JSONSetElement ( "{}" ;
	[ "column" ; _column ; JSONString ] ;
	[ "direction" ; _dir ; JSONString ]
	) ;
_q1 = JSONSetElement ( query ; "orderBys[" & _orderByCount & "]" ; _orderByObj ; JSONObject ) ;
_q2 = JSONSetElement ( _q1 ; "orderByCount" ; _orderByCount + 1 ; JSONNumber )
];
_q2
)

Let
(
[
_groupByCount = JSONGetElement ( query ; "groupByCount" ) ;
_fqName = GetFieldName ( column ) ;
_col = If ( Position ( _fqName ; "::" ; 1 ; 1 ) > 0 ; _fqName ; column ) ;
_column = QueryConvertField_cf ( _col )
];
JSONSetElement (
	JSONSetElement ( query ; "groupBys[" & _groupByCount & "]" ; _column ; JSONString ) ;
	"groupByCount" ; _groupByCount + 1 ; JSONNumber
)
)

Let
(
[
_havingCount = JSONGetElement ( query ; "havingCount" ) ;
_bindingCount = JSONGetElement ( query ; "bindingCount" ) ;
_fqName = GetFieldName ( column ) ;
_col = If ( Position ( _fqName ; "::" ; 1 ; 1 ) > 0 ; _fqName ; column ) ;
_column = QueryConvertField_cf ( _col ) ;
_havingObj = JSONSetElement ( "{}" ;
	[ "column" ; _column ; JSONString ] ;
	[ "operator" ; operator ; JSONString ] ;
	[ "boolean" ; "and" ; JSONString ]
	) ;
_q1 = JSONSetElement ( query ; "havings[" & _havingCount & "]" ; _havingObj ; JSONObject ) ;
_q2 = JSONSetElement ( _q1 ; "havingCount" ; _havingCount + 1 ; JSONNumber ) ;
_q3 = JSONSetElement ( _q2 ; "bindings[" & _bindingCount & "]" ; value ; JSONString ) ;
_q4 = JSONSetElement ( _q3 ; "bindingCount" ; _bindingCount + 1 ; JSONNumber )
];
_q4
)

// Assembles and returns the full SQL string without executing it.
// Useful for debugging. Bindings are represented as ? placeholders.
// Output is pretty-printed: each major clause on its own line,
// child items (fields, conditions, columns) indented with 4 spaces.
Let
(
[
_table = JSONGetElement ( query ; "table" ) ;
_selects = JSONGetElement ( query ; "selects" ) ;
_joins = JSONGetElement ( query ; "joins" ) ;
_joinCount = JSONGetElement ( query ; "joinCount" ) ;
_wheres = JSONGetElement ( query ; "wheres" ) ;
_whereCount = JSONGetElement ( query ; "whereCount" ) ;
_groupBys = JSONGetElement ( query ; "groupBys" ) ;
_groupByCount = JSONGetElement ( query ; "groupByCount" ) ;
_havings = JSONGetElement ( query ; "havings" ) ;
_havingCount = JSONGetElement ( query ; "havingCount" ) ;
_orderBys = JSONGetElement ( query ; "orderBys" ) ;
_orderByCount = JSONGetElement ( query ; "orderByCount" ) ;
_limit = JSONGetElement ( query ; "limit" ) ;
_offset = JSONGetElement ( query ; "offset" ) ;
_in = "    " ;
_selectFields = Substitute ( _selects ; ", " ; "," & ¶ & _in ) ;
_joinRaw = If ( _joinCount > 0 ; QueryBuildJoins_cf ( _joins ; _joinCount ; 0 ) ; "" ) ;
_joinSplit = Substitute ( Substitute ( _joinRaw ; " INNER JOIN " ; ¶ & "INNER JOIN " ) ; " LEFT JOIN " ; ¶ & "LEFT JOIN " ) ;
_joinClause = If ( _joinCount > 0 ;
	¶ & Substitute ( Substitute ( _joinSplit ; "INNER JOIN " ; "INNER JOIN" & ¶ & _in ) ; "LEFT JOIN " ; "LEFT JOIN" & ¶ & _in ) ;
	""
) ;
_whereRaw = If ( _whereCount > 0 ; QueryBuildWheres_cf ( _wheres ; _whereCount ; 0 ) ; "" ) ;
_whereClause = If ( _whereCount > 0 ;
	¶ & "WHERE" & ¶ & _in & Substitute ( Substitute ( _whereRaw ; " AND " ; ¶ & _in & "AND" & ¶ & _in ) ; " OR " ; ¶ & _in & "OR" & ¶ & _in ) ;
	""
) ;
_groupByRaw = If ( _groupByCount > 0 ; QueryBuildGroupBys_cf ( _groupBys ; _groupByCount ; 0 ) ; "" ) ;
_groupByClause = If ( _groupByCount > 0 ;
	¶ & "GROUP BY" & ¶ & _in & Substitute ( _groupByRaw ; ", " ; "," & ¶ & _in ) ;
	""
) ;
_havingRaw = If ( _havingCount > 0 ; QueryBuildHavings_cf ( _havings ; _havingCount ; 0 ) ; "" ) ;
_havingClause = If ( _havingCount > 0 ;
	¶ & "HAVING" & ¶ & _in & Substitute ( Substitute ( _havingRaw ; " AND " ; ¶ & _in & "AND" & ¶ & _in ) ; " OR " ; ¶ & _in & "OR" & ¶ & _in ) ;
	""
) ;
_orderByRaw = If ( _orderByCount > 0 ; QueryBuildOrderBys_cf ( _orderBys ; _orderByCount ; 0 ) ; "" ) ;
_orderByClause = If ( _orderByCount > 0 ;
	¶ & "ORDER BY" & ¶ & _in & Substitute ( _orderByRaw ; ", " ; "," & ¶ & _in ) ;
	""
) ;
_offsetClause = If ( not IsEmpty ( _offset ) ; ¶ & "OFFSET " & _offset & " ROWS" ; "" ) ;
_limitClause = If ( not IsEmpty ( _limit ) ; ¶ & "FETCH FIRST " & _limit & " ROWS ONLY" ; "" )
];
"SELECT" & ¶ & _in & _selectFields &
¶ & "FROM" & ¶ & _in & _table &
_joinClause &
_whereClause &
_groupByClause &
_havingClause &
_orderByClause &
_offsetClause &
_limitClause
)

// Executes the assembled query via ExecuteSQL using Evaluate to
// dynamically bind the stored parameter values.
// Returns "" if ExecuteSQL returns an error (result starting with "?").
Let
(
[
_sql = QueryToSQL_cf ( query ) ;
_bindings = JSONGetElement ( query ; "bindings" ) ;
_bindingCount = JSONGetElement ( query ; "bindingCount" ) ;
_bindingArgs = QueryBuildBindingArgs_cf ( _bindings ; _bindingCount ; 0 ) ;
_exprBase = "ExecuteSQL ( " & Quote ( _sql ) & " ; " & Quote ( fieldSeparator ) & " ; " & Quote ( rowSeparator ) ;
_expr = _exprBase & If ( _bindingCount > 0 ; " ; " & _bindingArgs ; "" ) & " )" ;
_result = Evaluate ( _expr )
];
If ( Left ( _result ; 1 ) = "?" ; "" ; _result )
)

// Executes the query and returns results as a JSON array of objects.
// Property names are derived automatically from the selectKeys stored in the
// query object, which QuerySelect_cf populates from the original column input.
// Returns "[]" when the query produces no rows or an error.
Let
(
[
_keys = JSONGetElement ( query ; "selectKeys" ) ;
_keyCount = ValueCount ( _keys ) ;
_rawResult = QueryGet_cf ( query ; Char ( 28 ) ; "¶" ) ;
_rowCount = If ( IsEmpty ( _rawResult ) ; 0 ; ValueCount ( _rawResult ) )
];
If ( _rowCount = 0 ;
	"[]" ;
// ELSE
	QueryBuildJsonRows_cf ( "[]" ; _rawResult ; _rowCount ; _keys ; _keyCount ; 1 )
)
)

// Returns JSONGetElement( json ; property ) where property is resolved from
// the field argument using this priority order:
//   1. GetFieldName( field ) — works when field is a real FM field reference;
//      strips the table occurrence prefix (everything before ::)
//   2. field contains :: — strips the table prefix from the string value
//   3. Fallback — assumes field is already the intended property name string
// If index is provided (non-empty), JSONGetElement( json ; index ) is evaluated
// first to extract an array element, and the property lookup runs on that result.
// Returns "?" if the working JSON does not pass JSON validation.
Let
(
[
_working = If ( not IsEmpty ( index ) ; JSONGetElement ( json ; index ) ; json ) ;
_isValidJson = not Exact ( Left ( JSONFormatElements ( _working ) ; 1 ) ; "?" ) ;
_fqName = GetFieldName ( field ) ;
_colonPos = Position ( field ; "::" ; 1 ; 1 ) ;
_property = Case (
	not IsEmpty ( _fqName ) and Position ( _fqName ; "::" ; 1 ; 1 ) > 0 ;
		Middle ( _fqName ; Position ( _fqName ; "::" ; 1 ; 1 ) + 2 ; Length ( _fqName ) ) ;
	not IsEmpty ( _fqName ) ;
		_fqName ;
	_colonPos > 0 ;
		Middle ( field ; _colonPos + 2 ; Length ( field ) ) ;
	// ELSE
	field
	)
];
Case (
	not _isValidJson ;
		"?" ;
	// ELSE
	JSONGetElement ( _working ; _property )
	)
)
